const b = $json.body || {};
const esc = (v = '-') => String(v ?? '-').replace(/[&<>\"']/g, (m) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '\"': '&quot;', "'": '&#39;' }[m]));
const money = (n) => `Rp${Number(n || 0).toLocaleString('id-ID')}`;
const dateLabel = b.date ? new Intl.DateTimeFormat('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' }).format(new Date(`${b.date}T00:00:00+07:00`)) : '-';
const text = `🟡 <b>CourtFlow — Booking Baru</b>
━━━━━━━━━━━━━━━━
<b>ID Booking:</b> #${esc(b.bookingId)}
<b>Pelanggan:</b> ${esc(b.userName)}
<b>Email:</b> ${esc(b.userEmail)}
<b>Lapangan:</b> ${esc(b.courtName)}
<b>Jadwal:</b> ${esc(dateLabel)}
<b>Jam:</b> ${esc(b.startTime)}–${esc(b.endTime)} WIB
<b>Total:</b> ${money(b.totalPrice)}
<b>Status:</b> Menunggu pembayaran
━━━━━━━━━━━━━━━━
Silakan cek dashboard admin untuk follow-up pembayaran.`;
return [{ json: {
  timestamp: new Date().toISOString(),
  event: 'booking_created',
  booking_id: b.bookingId || '',
  user_name: b.userName || '',
  user_email: b.userEmail || '',
  court_name: b.courtName || '',
  date: b.date || '',
  start_time: b.startTime || '',
  end_time: b.endTime || '',
  status: b.status || 'Menunggu pembayaran',
  total_price: Number(b.totalPrice || 0),
  chat_id: $env.TELEGRAM_CHAT_ID || '',
  telegram_url: 'https://api.telegram.org/bot' + ($env.TELEGRAM_BOT_TOKEN || '') + '/sendMessage',
  text,
  data: b,
} }];

